var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"짜잔! 아카데미 최고의 마술사 미카★스타 등장!","JPN":"ジャジャーン！　アカデミー最高のマジシャン、ミカ★スター登場！","ENG":"Tah-dah! Here comes the Academy's greatest magician, Mika★Star!","TWN":"鏘鏘～～！！學院最偉大的魔術師米卡★斯塔～登場～拍手！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어때? 이번에 연습한 새 마술! 노크한 문 반대편에서 나오기야!","JPN":"どう？　最近練習している新マジック！ ノックしたドアの反対側から出てくるの！","ENG":"What do you think? It's my new magic trick, showing up on the other side of the door that I knocked!","TWN":"想看我最新練習的魔術嗎？這個魔術叫作任意門！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"앗, 이번에도 호응 고마워! 난 사장님처럼 리액션이 풍부한 관객을 정말 사랑해!","JPN":"あっ、今回も反応ありがとう！　私は社長みたいにリアクション豊富な観客が一番好きなの！","ENG":"Ah, thank you for your response. I love such responsive fans like you!","TWN":"嘻～老闆這次也很捧場呢！謝謝老闆～我超愛像你這種會互動的觀眾！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"응? 다른 마술도 보고 싶어?","JPN":"ん？　他のマジックも見たいの？","ENG":"Mm? Want to see more magic tricks?","TWN":"哦？你還想看其他的魔術喔？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"자, 그럼 잘 봐! 여기 몽땅 연필이 있지?","JPN":"じゃあ、よーく見てね！　ここに小さい鉛筆があるよ。","ENG":"Okay, then watch. See this pencil stub?","TWN":"好吧！那你睜大眼睛看好囉！這是一支鉛筆！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"짠! 사라졌어요! 어디로 갔을까?","JPN":"ジャーン！　消えました！　どこに消えたのでしょう？","ENG":"Voila—it's gone! Where do you think it's gone?","TWN":"鏘！鉛筆不見了！跑到哪裡去了呢？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"보시라! 사장님의 소매 안에서 아까 그 몽땅 연필이......!","JPN":"ほら！　社長の袖の中からさっきの鉛筆が……！","ENG":"Behold! That pencil stub is inside your sleeve—","TWN":"老闆！快看看你的口袋，鉛筆是不是在......！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"연필이...... 아니라, 어째서 계약서가......?","JPN":"鉛筆……じゃなくて、どうして契約書が……？","ENG":"It's not the pencil stub; it's a contract. How?","TWN":"怎麼不是鉛筆......是契約書......？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"게다가 어째서 계약서에 내가 한 적 없는 미카★스타 전용 친필사인까지!","JPN":"しかも契約書には書いた覚えのないミカ★スター専用の直筆サインまで？","ENG":"It's even signed Mika★Star, even though I've never signed such a contract!","TWN":"而且上面竟然還有我米卡★斯塔的親筆簽名？我不記得我有簽過呀？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐어? 내가 저번에 가르쳐준 걸 조금 응용했을 뿐이라고?","JPN":"なにぃ？　この前私が教えたトリックを少し応用しただけ？","ENG":"What? You just applied the trick I taught you before?","TWN":"什麼？你只是稍微耍了一下我上次教你的手法？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"괴, 굉장해! 어떤 트릭을 쓴 거야? 나도 알고 싶어!","JPN":"す、すごい！　どんなトリックなの？　私も知りたい！","ENG":"I-incredible! What kind of trick is this? I want to know!","TWN":"好…好厲害！你是怎麼騙過我的？快點跟我說！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"......아, 아니지. 마술사의 트릭은 마술사만 알고 있을 때 가장 아름다운 법!","JPN":"……えっと、違う違う。マジシャンのトリックは本人だけが知っている時が一番輝くもの！","ENG":"... Oh, never mind. A magician's trick is sacred. I must covet yours.","TWN":"…… 還是不要好了！魔術師的手法一旦破解了就不美了！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"좋아! 결정했어! 사장님은 이제부터 내 숙명의 라이벌이야!","JPN":"よし、決めた！　社長はこれから私の宿命のライバルだよ！","ENG":"Alright, I've made up my mind. Boss, as of this moment, you're my fated rival!","TWN":"好！就決定是你了！現在起，老闆就是我命中注定的對手囉！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"사장님을 뛰어넘은 마술사가 되는 그날까지! 난 여기 남아서 계속 성장하겠어!","JPN":"社長を超えるマジシャンになる日まで！　私はこの会社で成長し続ける！","ENG":"I'll stay here and continue to grow until the day I outshine you as a magician.","TWN":"在我成為超越老闆的魔術師之前，我會留在你身邊不斷突破的！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};